import UIKit
import Security

class CryptoWallet {
    var privateKey: SecKey?
    var publicKey: SecKey?

    init() {
        generateKeyPair()
    }

    func generateKeyPair() {
        let attributes: [String: Any] = [
            kSecAttrKeyType as String: kSecAttrKeyTypeECSECPrimeRandom,
            kSecAttrKeySizeInBits as String: 256,
            kSecPrivateKeyAttrs as String: [
                kSecAttrIsPermanent as String: true,
                kSecAttrApplicationTag as String: "com.example.keys.mykey"
            ]
        ]

        var error: Unmanaged<CFError>?
        privateKey = SecKeyCreateRandomKey(attributes as CFDictionary, &error)
        guard let privateKey = privateKey else {
            print("Error generating private key: \(String(describing: error))")
            return
        }
        publicKey = SecKeyCopyPublicKey(privateKey)
    }

    func signTransaction(transactionData: Data) -> Data? {
        guard let privateKey = privateKey else { return nil }
        var error: Unmanaged<CFError>?
        let signature = SecKeyCreateSignature(privateKey,
                                              .ecdsaSignatureMessageX962SHA256,
                                              transactionData as CFData,
                                              &error) as Data?
        if let error = error {
            print("Error signing transaction: \(error)")
            return nil
        }
        return signature
    }
}

class BlockchainCommunicator {
    func broadcastTransaction(signedTransaction: Data) {
        guard let url = URL(string: "https://your-blockchain-node.com/transaction") else { return }
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.httpBody = signedTransaction
        request.setValue("application/octet-stream", forHTTPHeaderField: "Content-Type")
        
        let task = URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                print("Failed to broadcast transaction: \(error)")
                return
            }
            if let httpResponse = response as? HTTPURLResponse,
               httpResponse.statusCode == 200 {
                print("Transaction broadcasted successfully")
            } else {
                print("Failed to broadcast transaction with response: \(String(describing: response))")
            }
        }
        task.resume()
    }
}

